import React, { useMemo } from "react";
import { ScrollView, View } from "react-native";
import type { IResponsiveElement } from "@lmb-it/kitsconcerto-types";
import {
  Box,
  Button,
  Card,
  Center,
  Grid,
  GridItem,
  Heading,
  HStack,
  Image,
  Pressable,
  Skeleton,
  Text,
  VStack,
} from "..";
import { style } from "./helpers/style";

const COMPONENT_MAP: Record<string, React.ElementType<any>> = {
  Button,
  Svg: View,
  List: View,
  ListItem: View,
  a: Pressable,
  Pressable: Pressable,
  Box,
  Image,
  Grid,
  GridItem,
  Card,
  Text,
  Heading,
  Center,
  Skeleton,
  HStack,
  VStack,
  ScrollView: ScrollView,
};

export default function useResponsiveBuilder<T>(
  props: React.PropsWithChildren<IResponsiveElement<T>>,
  ref?: React.Ref<any>
): React.ReactElement {
  const {
    additionalStyles = {},
    additionalClasses,
    nativeProps,
    cssProps,
    children,
    as,
    scrollable,
  } = props;

  const combinedStyles = useMemo(() => {
    return [
      style({
        ...additionalStyles,
        ...cssProps,
        ...nativeProps?.style,
      }),
    ];
  }, [cssProps, additionalStyles, nativeProps?.style]);

  const Component = as ? COMPONENT_MAP[as] || View : View;

  const isText =
    (typeof children === "string" || typeof children === "number") &&
    as !== "Heading" &&
    as !== "Text";

  const content = (
    <Component
      ref={ref}
      {...nativeProps}
      style={combinedStyles}
      className={additionalClasses}
    >
      {isText ? <Text>{children}</Text> : children}
    </Component>
  );

  if (scrollable) {
    return <ScrollView horizontal={as === 'HStack'}>{content}</ScrollView>;
  }

  return content;
}
